  ('judicial-f0899a01-moex-00126', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '關於我國刑法對於正犯與共犯之概念，下列敘述何者正確？', '["係採單一正犯概念", "係採共犯獨立性概念", "係採區分正共犯概念", "並無共犯之獨立規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00127', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲、乙共謀前往A宅竊盜，A宅鄰居丙聽到，決定暗助甲、乙兩人，於是當天晚上故意在A宅旁放梯子， 甲、乙即直接使用該梯子翻入A宅行竊得手。丙之刑責為何？', '["加重竊盜罪之共同正犯", "加重竊盜罪之教唆犯", "加重竊盜罪之幫助犯", "加重竊盜罪之間接正犯"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00128', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲因犯罪被起訴，甲之律師丙於是和證人乙商討，希望證人乙在法庭上作偽證說甲不在犯罪現場，乙果依 丙之要求而作偽證。丙成立何罪？', '["偽證罪的教唆犯", "偽證罪之正犯", "偽證罪之間接正犯", "偽證罪之共同正犯"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00129', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '關於刑法之沒收，下列何者正確？', '["沒收只能對犯罪人行之，對第三人不能沒收", "犯罪所得屬於義務沒收之類型", "犯罪所得之沒收不以違法行為為前提", "只有犯罪人擁有所有權的犯罪所得，才是沒收的對象"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00130', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '下列何種情形不可以追徵犯罪所得之價額？', '["全部不能沒收", "一部不能沒收", "不宜執行沒收", "犯罪所得已實際合法發還被害人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00131', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲見乙當街對丙為強盜行為，乙奪取財物後欲離開現場，甲上前欲逮捕乙，竟遭乙毆打，甲腿部扭傷倒地 不起，乙遂持贓物離開現場。有關乙之行為，下列敘述何者正確？', '["乙對丙成立強盜既遂罪，對甲成立普通傷害罪，兩罪數罪併罰", "乙對丙成立強盜既遂罪，對甲成立普通傷害罪，兩罪想像競合", "乙對丙成立強盜既遂罪，對甲成立準強盜罪，兩罪數罪併罰", "乙對丙成立強盜既遂罪，對甲成立準強盜罪，兩罪想像競合"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00132', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '關於數罪併罰，下列敘述何者正確？', '["宣告多數無期徒刑者，不問情狀，一律終身監禁，不得假釋", "宣告多數褫奪公權者，合併計算期間而執行之", "宣告多數罰金者，從一重處斷", "宣告多數有期徒刑時，定執行刑不得逾30年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00133', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '有關刑之減輕，下列敘述何者正確？', '["滿80歲人犯罪，本刑為死刑或無期徒刑者，減輕其刑", "犯罪之情狀顯可憫恕，認科以最高度刑仍嫌過重者，得酌量減輕其刑", "依法律加重或減輕者，不得再依刑法第59條之規定酌量減輕其刑", "無期徒刑減輕者，為15年以下10年以上有期徒刑"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00134', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '有關緩刑之敘述，下列何者錯誤？', '["行為人受3年以下有期徒刑之宣告時，法院得宣告緩刑", "若在緩刑期間內故意犯他罪而受7個月有期徒刑之宣告確定時，得撤銷緩刑", "緩刑期滿未經撤銷時，刑之宣告失其效力", "在宣告緩刑時得命犯罪行為人向被害人道歉"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00135', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '關於罪刑法定原則敘述，下列何者錯誤？', '["絕對不定期刑之規定違反罪刑法定原則", "依學說見解，罪刑法定原則亦許可有利行為人之類推適用", "超法規阻卻違法事由之適用違反罪刑法定原則", "罪刑法定原則包括罪刑明確性之要求"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL)
